// // This module decrements the 4-bit binary counter on the rising edge of Clk2 when offsetDec is asserted and resets it to zero when Reset is active.
module top_module(output reg [3:0] offset, input Reset, input Clk2,
    input offsetInc);always@(posedge Clk2) begin
    if (Reset)
      offset <= 4'b0;
    else
      if (offsetInc)
        offset <= offset + 1;
      else
        offset <= offset;
  end

endmodule
